{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from single-recipient to multi-recipient shipments. This is a fundamental change to the Shipment aggregate root, affecting its cardinality relationship with Recipient. The change impacts 2 million existing production records and external partner API contracts.",
    "bounded_context": "Shipment Fulfillment — the context that owns the lifecycle of a shipment from creation through delivery. The Recipient entity is a core concept within this context, and changing its cardinality ripples into adjacent contexts: Routing, Notifications, Billing, and Partner Integration.",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "The aggregate root representing a physical package or consignment moving through the delivery network from origin to one or more destinations." },
      { "term": "Recipient", "definition": "A value object or entity representing a person or entity receiving a delivery, including their name, address, phone number, and delivery preferences." },
      { "term": "Delivery Preferences", "definition": "Recipient-specific instructions governing how and when delivery should occur (e.g., safe place, signature required, time window, authority to leave)." },
      { "term": "Primary Recipient", "definition": "The first or default recipient on a multi-recipient shipment; critical for backward compatibility and single-point-of-contact scenarios." },
      { "term": "Multi-Recipient Shipment", "definition": "A shipment with more than one recipient, each potentially at a different address with different delivery preferences. Raises questions about whether this is one physical package with multiple stops or multiple packages under one logical shipment." },
      { "term": "Partner API Contract", "definition": "The agreed-upon data format and semantics used to exchange shipment data with external partner systems." },
      { "term": "Shipment Leg", "definition": "A segment of a multi-recipient shipment's journey between two consecutive delivery points." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment must have at least one Recipient at all times.",
      "invariant": true,
      "invariant_justification": "A shipment without a recipient is physically meaningless — there is no delivery without a destination. This is a state integrity constraint: the system is corrupt if violated.",
      "testable_assertion": "Given a Shipment, the recipient collection must never be empty. Any operation that would remove the last recipient must be rejected."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient on a Shipment must have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum data required to attempt a physical delivery and contact the recipient. Without them, the courier cannot fulfill the shipment.",
      "testable_assertion": "Given a Recipient being added to a Shipment, creation must fail if name is blank, address is not a valid deliverable address, or phone number is not a valid contactable number."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient on a Shipment must have an independent delivery status.",
      "invariant": true,
      "invariant_justification": "In a multi-recipient shipment, one recipient may receive their delivery while another has not. The Shipment's overall status is derived from the individual recipient delivery statuses. If statuses are conflated, the system misrepresents physical reality.",
      "testable_assertion": "Given a Shipment with Recipients A and B, when A's delivery is completed but B's is not, then A's status is 'delivered' and B's status remains 'in_transit', and the Shipment's aggregate status reflects partial fulfillment."
    },
    {
      "id": "BR-4",
      "rule": "Delivery preferences are scoped to each individual Recipient, not to the Shipment as a whole.",
      "invariant": true,
      "invariant_justification": "Different recipients at different addresses have different physical constraints and personal requirements. Conflating preferences across recipients would result in incorrect delivery behavior — e.g., leaving a signature-required package at a safe place.",
      "testable_assertion": "Given a Shipment with Recipient A (preference: signature required) and Recipient B (preference: leave at door), the delivery instructions for A must require signature and for B must allow safe-place delivery, independently."
    },
    {
      "id": "BR-5",
      "rule": "Existing single-recipient shipments must remain fully functional and queryable without data loss after the model evolution.",
      "invariant": true,
      "invariant_justification": "2 million production records represent real business commitments. Data corruption or inaccessibility would violate contractual obligations and break auditability.",
      "testable_assertion": "Given any pre-migration single-recipient Shipment, after migration it must be retrievable with all original fields intact, and its single recipient must appear as the sole entry in the recipients collection."
    },
    {
      "id": "BR-6",
      "rule": "The Shipment is only considered fully delivered when ALL recipients have received their deliveries.",
      "invariant": false,
      "invariant_justification": "This is a business policy decision. A VP could decide that partial delivery counts as 'delivered' for SLA purposes. The exact completion semantics are a policy, not a physical constraint.",
      "testable_assertion": "Given a Shipment with 3 recipients, the Shipment status must not be 'delivered' until all 3 recipient deliveries are confirmed (under current policy)."
    },
    {
      "id": "BR-7",
      "rule": "External partner APIs must continue to receive shipment data in a format they can process, even for multi-recipient shipments.",
      "invariant": false,
      "invariant_justification": "API contract evolution is a business coordination problem, not a physical constraint. Partners can be migrated on a timeline, and interim compatibility layers are a policy choice.",
      "testable_assertion": "Given a multi-recipient Shipment sent to a partner on API v1 (single-recipient format), the system must either send one message per recipient or send only the primary recipient, per the agreed compatibility policy."
    },
    {
      "id": "BR-8",
      "rule": "Recipients within a single Shipment must have an explicit ordering that determines the delivery sequence.",
      "invariant": false,
      "invariant_justification": "Delivery sequencing is an optimization and operational policy — it can change based on routing efficiency, priority, or business rules. But some ordering must exist to plan the route.",
      "testable_assertion": "Given a Shipment with multiple Recipients, the system must maintain a delivery order, and a courier must be able to query the next recipient to deliver to."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The creator provides one or more Recipients, each with name, address, phone, and delivery preferences",
      "then": "The Shipment is created with all Recipients associated, each retaining their individual delivery preferences and an independent delivery status initialized to 'pending'"
    },
    {
      "id": "AC-2",
      "given": "An existing single-recipient Shipment created before the migration",
      "when": "The Shipment is queried after the model evolution",
      "then": "The Shipment returns its original Recipient as the sole entry in a recipients collection, with all original data preserved and no data loss"
    },
    {
      "id": "AC-3",
      "given": "A multi-recipient Shipment where Recipient A has been delivered",
      "when": "The Shipment status is queried",
      "then": "The Shipment status reflects 'partially_delivered' (or equivalent), Recipient A shows 'delivered', and remaining recipients show their current individual statuses"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment is sent to an external partner via the existing API",
      "when": "The partner system receives the data",
      "then": "The data is in a format the partner can process — either via a compatibility layer (e.g., one call per recipient) or by sending only the primary recipient with a flag indicating additional recipients exist"
    },
    {
      "id": "AC-5",
      "given": "A Shipment with multiple Recipients",
      "when": "An operation attempts to remove the last remaining Recipient",
      "then": "The operation is rejected and the Shipment retains at least one Recipient"
    },
    {
      "id": "AC-6",
      "given": "A Shipment with two Recipients at different addresses, each with different delivery preferences",
      "when": "The courier views delivery instructions for each stop",
      "then": "Each stop displays the correct, recipient-specific delivery preferences — preferences are never mixed or inherited from another recipient"
    },
    {
      "id": "AC-7",
      "given": "The 2 million existing shipments in production",
      "when": "The data migration is executed",
      "then": "All shipments are migrated to the new schema with zero data loss, zero downtime for reads, and the migration is reversible within a defined rollback window"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A multi-recipient Shipment where two recipients share the same address but have different delivery preferences",
      "expected_behavior": "Both recipients are treated as distinct deliveries with their own preferences and statuses, even though the physical address is identical. The system must not deduplicate or merge them."
    },
    {
      "scenario": "A recipient is added to a Shipment that is already in transit",
      "expected_behavior": "The business must define whether mid-transit recipient additions are allowed. If allowed, routing must be recalculated. If not, the operation must be rejected with a clear reason. This is a critical policy decision."
    },
    {
      "scenario": "One recipient on a multi-recipient Shipment refuses delivery",
      "expected_behavior": "Only that recipient's status changes to 'refused'. Other recipients are unaffected. The shipment-level status reflects partial delivery. Return/retry policy applies only to the refusing recipient."
    },
    {
      "scenario": "External partner queries a multi-recipient shipment by the old single-recipient tracking number",
      "expected_behavior": "The system must resolve the query and return data in the partner's expected format. If the partner only understands single-recipient responses, a compatibility strategy must be defined (e.g., return primary recipient only, or return an error with upgrade instructions)."
    },
    {
      "scenario": "A Shipment has 50+ recipients (bulk/corporate use case)",
      "expected_behavior": "The system must handle large recipient lists without performance degradation. Pagination, batch processing, and route optimization must scale. Upper bounds on recipient count should be defined as a business policy."
    },
    {
      "scenario": "Billing for a multi-recipient Shipment — is it one charge or per-recipient?",
      "expected_behavior": "Billing model must be explicitly defined before implementation. A single-charge model vs per-recipient-stop model has fundamentally different pricing implications. This decision affects the entire commercial model."
    },
    {
      "scenario": "Notification routing for delivery updates on multi-recipient shipments",
      "expected_behavior": "Each recipient receives notifications only about their own delivery, not about other recipients' deliveries. The shipment creator/sender may receive aggregate notifications about all recipients."
    }
  ],

  "business_impact": {
    "financial": "High impact. Pricing model must be revisited — multi-recipient shipments may require per-stop pricing, route-based pricing, or bundled pricing. Revenue opportunity exists (new product offering for businesses doing multi-drop deliveries), but incorrect pricing could result in margin erosion. Migration costs include engineering time, partner coordination, and potential downtime risk on 2M records.",
    "operational": "Very high impact. Route optimization algorithms must change from point-to-point to multi-stop. Courier workload per shipment increases. Delivery SLA definitions change — 'on-time' now means all recipients delivered on time, or is it per-recipient? Dispatch and load planning become more complex. Status tracking and customer support workflows must handle partial delivery states.",
    "user": "Moderate positive impact for senders who currently create multiple shipments for multi-recipient needs. Potentially confusing for recipients who now share a shipment — they need clarity that their delivery is independent. Courier experience changes significantly: multi-stop routes, multiple delivery confirmations per shipment, more complex exception handling.",
    "risk": "High risk. Data migration of 2M records is non-trivial. External partner API breaking changes could cause integration failures. Domain model change is foundational — if the cardinality is wrong or the aggregate boundary is misdrawn, it will be extremely expensive to fix later. There is also a semantic risk: does 'multi-recipient shipment' mean one package with multiple stops, or multiple packages grouped logically? This ambiguity MUST be resolved before implementation.",
    "stakeholders_affected": [
      { "group": "Senders/Shippers", "impact": "Gain ability to create multi-recipient shipments, reducing operational overhead. Must learn new creation flows." },
      { "group": "Recipients", "impact": "Experience is largely unchanged for single-recipient shipments. For multi-recipient, must be clear their delivery is tracked independently." },
      { "group": "Couriers/Drivers", "impact": "Significant workflow change — multi-stop routes, multiple proof-of-delivery captures per shipment, more complex exception handling per stop." },
      { "group": "External Partners", "impact": "API contract change requires coordination. Partners on v1 API need a compatibility strategy or migration timeline. Risk of integration failures if not managed." },
      { "group": "Customer Support", "impact": "Must handle new status types (partially_delivered), recipient-specific inquiries within a single shipment, and more complex dispute resolution." },
      { "group": "Finance/Billing", "impact": "Pricing model must be redefined. Invoicing, refunds, and revenue recognition become more complex with per-recipient granularity." },
      { "group": "Product/Analytics", "impact": "KPIs and reporting must be updated. 'Delivery success rate' now has shipment-level and recipient-level dimensions." }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec describes a cardinality change but leaves critical domain semantics unresolved. The most fundamental question — whether a multi-recipient shipment is one physical package making multiple stops or multiple physical packages grouped under one logical shipment — is not answered. This distinction changes everything: aggregate boundaries, routing, billing, status modeling, and physical fulfillment. Additionally, delivery preferences are mentioned without defining what they include. The external partner compatibility strategy is unspecified. These are not implementation details — they are domain-defining decisions that must be made before any correct implementation is possible.",
    "high_confidence_areas": [
      "At-least-one-recipient invariant is unambiguous",
      "Existing data must be preserved without loss",
      "Recipient-level delivery preferences must remain independent",
      "Per-recipient delivery status tracking is required",
      "External partner API compatibility must be managed"
    ],
    "low_confidence_areas": [
      "Physical semantics: one package multi-stop vs multiple packages grouped logically",
      "What constitutes 'delivery preferences' — no enumeration provided",
      "Billing model for multi-recipient shipments",
      "Whether recipients can be added/removed after shipment creation or while in transit",
      "Upper bound on number of recipients per shipment",
      "Partner API compatibility strategy (fan-out, primary-only, or versioned API)"
    ],
    "assumptions": [
      "Multi-recipient means one physical consignment making multiple delivery stops (not multiple independent packages)",
      "Existing single-recipient shipments will be migrated in-place to the new schema, not dual-written",
      "Delivery preferences include at minimum: safe-place authorization, signature requirement, and time window preferences",
      "There will be a concept of 'primary recipient' for backward compatibility"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not clarify whether a multi-recipient Shipment represents one physical package making multiple stops, or multiple physical packages grouped under a single logical Shipment. This distinction fundamentally changes the domain model, aggregate boundaries, routing, and billing.",
      "affected_stakeholders": ["Product", "Engineering", "Couriers", "Finance"],
      "options": [
        "A: One physical package, multiple delivery stops (hub-and-spoke or sequential route)",
        "B: Multiple physical packages under one logical shipment (each independently routed)",
        "C: Both patterns supported, distinguished by a shipment type field"
      ],
      "recommendation": "Resolve this before any implementation begins. If A, the Shipment aggregate owns the route and recipient ordering matters. If B, each Recipient essentially becomes a sub-shipment with its own tracking. Option C adds significant complexity and should only be chosen if both use cases are validated with customers."
    },
    {
      "type": "ambiguity",
      "description": "'Delivery preferences' is referenced but never enumerated. The set of valid preferences defines the Recipient value object's shape and directly impacts courier workflows, UI design, and partner API contracts.",
      "affected_stakeholders": ["Product", "Engineering", "Couriers", "Partners"],
      "options": [
        "A: Define a minimal set (signature required, safe place, time window) and extend later",
        "B: Make preferences a flexible key-value map",
        "C: Full enumeration from product team before implementation"
      ],
      "recommendation": "Option C is ideal but may delay. Recommend Option A with an extensibility path — define the 3-5 most common preferences now, with a schema that allows adding more without breaking changes."
    },
    {
      "type": "missing_context",
      "description": "No billing model defined for multi-recipient shipments. This is not a downstream concern — it is a core domain decision that affects whether recipients are modeled as independent cost centers or as stops within a single priced route.",
      "affected_stakeholders": ["Finance", "Product", "Senders"],
      "options": [
        "A: Flat rate per shipment regardless of recipient count",
        "B: Base rate + per-additional-recipient surcharge",
        "C: Per-stop pricing based on route distance"
      ],
      "recommendation": "Product and Finance must align on this before the domain model is finalized. The billing model constrains the domain model — not the other way around."
    },
    {
      "type": "missing_context",
      "description": "External partner API compatibility strategy is undefined. With partners currently receiving single-recipient format, a breaking change could cause integration failures. The strategy must be defined at the domain level, not deferred to implementation.",
      "affected_stakeholders": ["External Partners", "Engineering", "Product"],
      "options": [
        "A: API versioning — partners migrate to v2 on their timeline, v1 sends primary recipient only",
        "B: Fan-out — one API call per recipient for v1 partners",
        "C: Envelope pattern — v1 response includes primary recipient plus a 'has_additional_recipients' flag"
      ],
      "recommendation": "Option A with Option C as the v1 compatibility layer. Partners get time to migrate, but are aware that multi-recipient shipments exist."
    }
  ],

  "rejection_reasons": []
}

